package com.android.zubanx.feature.story.data

object StoryData {

    val stories: Map<StoryCategory, List<StoryEntry>> = mapOf(
        StoryCategory.Adventure to listOf(
            StoryEntry("adv_1", "The Lost Map",
                "A young explorer named Amir found an old map in his grandfather's attic. The map showed a path through the mountains to a hidden valley. He packed his bag and set off early in the morning. The trail was steep and the wind was cold, but he kept moving. By noon, he reached the top of the ridge. Below him stretched a green valley filled with wild flowers and a sparkling river. Amir smiled. The journey had been hard, but the view made every step worth it. He sat down to rest and promised himself he would return with his friends next summer."),
            StoryEntry("adv_2", "Crossing the River",
                "Sara had always been afraid of water. But when the bridge was washed away by the flood, the only way home was across the river. She stood at the edge, heart pounding. An old fisherman appeared with a small boat. He offered to take her across. She hesitated, then stepped in. The current was strong, but the fisherman rowed steadily. In minutes, they reached the other side. Sara thanked him and walked home dry. That evening, she realised that courage was not the absence of fear — it was choosing to move forward despite it."),
            StoryEntry("adv_3", "Night in the Forest",
                "The hiking group made a wrong turn and darkness fell before they found the camp. They had one torch and low phone batteries. Leila, the youngest in the group, remembered her father teaching her to navigate by stars. She looked up and found the North Star. Step by step, she led the group back to the trail. Two hours later, they reached camp. The guide apologised; Leila just laughed. Back home, her father framed her photo from that night. Underneath it, he wrote: 'She found her way.'"),
            StoryEntry("adv_4", "The Diving Lesson",
                "On his first day at the coast, Khalid refused to dive into the sea. The water looked too deep, too dark. His cousin laughed and jumped in without hesitation. Khalid watched. Then, slowly, he climbed to the edge. He counted to three — and jumped. The cold water hit him like a wall. He surfaced gasping, then laughing. 'Again!' he shouted. By sunset, he had dived twelve times. Fear, he learned, has a short memory once you have faced it."),
            StoryEntry("adv_5", "The Old Lighthouse",
                "The lighthouse had been dark for thirty years. The town council wanted it torn down. But Fatima, a retired engineer, believed it could still guide ships safely. She spent three months rewiring the lamp and repainting the tower alone. On the night she switched it on, ships in the harbour tooted their horns. The council changed their vote. The lighthouse still stands today with a small plaque: 'Restored by one person who refused to give up.'")
        ),
        StoryCategory.History to listOf(
            StoryEntry("his_1", "The First Library",
                "More than two thousand years ago, the city of Alexandria in Egypt was home to the greatest library in the ancient world. Scholars from across the Mediterranean came to read its scrolls. The library held texts on medicine, astronomy, poetry, and philosophy. Copies of every book that passed through the city's port were made and kept. Though the library no longer exists, the idea it represented — that knowledge should be gathered, shared, and protected — inspired libraries in every country and every age that followed."),
            StoryEntry("his_2", "A Letter from the Front",
                "During the war, a soldier named Hassan wrote letters home every week. He described the cold, the noise, and the long waiting. But he also wrote about the small kindnesses — a shared meal, a stranger's map, a song someone sang at night. His daughter kept every letter. Years later, she published them as a book. Readers were moved not by the battles but by the ordinary moments of humanity in an extraordinary time. The book is still in print today."),
            StoryEntry("his_3", "The Printing Press",
                "Before the printing press, books were copied by hand. One book could take a monk a full year to copy. Most people never owned a single book in their lives. When Gutenberg built his printing press in the 1440s, everything changed. A page that once took hours to copy could now be printed in minutes. Ideas spread faster than ever before. Within fifty years, millions of books existed in Europe. The printing press did not just change reading — it changed the world."),
            StoryEntry("his_4", "The Silk Road",
                "For centuries, merchants, pilgrims, and explorers travelled the Silk Road — a web of routes connecting China to the Mediterranean. They carried silk, spices, glass, and gold. But they also carried something less visible: ideas. Mathematics from India, astronomy from Persia, paper from China, and philosophy from Greece all travelled these routes. Languages mixed. Religions spread. The Silk Road was not just a trade route — it was the internet of the ancient world."),
            StoryEntry("his_5", "The Night the Wall Fell",
                "On a November night in 1989, crowds gathered at the Berlin Wall. For nearly thirty years, the wall had divided families and friends. Guards stood at checkpoints. No one was allowed to cross without permission. Then, a confused announcement on the radio said the border was open. Thousands of people rushed to the wall. Some climbed it. Others hugged strangers. Hammers appeared. Piece by piece, the wall came down. By morning, people who had not seen each other in decades were standing together on the same street.")
        ),
        StoryCategory.Science to listOf(
            StoryEntry("sci_1", "The First Breath of Oxygen",
                "In 1774, the chemist Joseph Priestley heated a red powder in a sealed glass jar. A gas rose from it. A candle burned brighter in it. A mouse stayed alive longer inside it. Priestley had discovered oxygen, though he did not know its name yet. He called it 'dephlogisticated air.' A French chemist named Lavoisier later named it oxygen and proved it was essential to breathing and burning. What began as curiosity about a red powder changed our understanding of the air we breathe."),
            StoryEntry("sci_2", "The Falling Apple",
                "The story of Newton and the apple may be partly legend, but the physics is real. Isaac Newton spent years thinking about why the Moon does not fall to Earth. He realised that the Moon is falling — it just moves sideways fast enough to keep missing the Earth. The same force that pulls an apple down also holds the Moon in orbit. He called it gravity. This one idea — that the same force applies everywhere in the universe — is one of the greatest scientific leaps in human history."),
            StoryEntry("sci_3", "Inside the Atom",
                "For most of human history, people believed matter could not be broken into anything smaller than an atom. Then, in 1897, J.J. Thomson discovered the electron — a particle inside the atom. A few years later, Rutherford showed that the atom had a tiny, dense nucleus at its centre. Then protons and neutrons were found inside the nucleus. Today, physicists know that protons and neutrons are made of even smaller particles called quarks. Every decade, the smallest known thing gets smaller."),
            StoryEntry("sci_4", "The Accidental Antibiotic",
                "In 1928, Alexander Fleming returned from holiday to find mould growing on a petri dish in his laboratory. He was about to throw it away when he noticed something unusual: the bacteria around the mould were dead. The mould was producing something that killed bacteria. Fleming called it penicillin. At the time, bacterial infections killed millions of people every year. Penicillin changed medicine forever. A forgotten petri dish became one of the greatest medical discoveries of the twentieth century."),
            StoryEntry("sci_5", "The Speed of Light",
                "For centuries, scientists debated whether light had a speed at all. Some believed it travelled instantly. In 1676, astronomer Ole Rømer noticed that eclipses of Jupiter's moon happened later than expected when Earth was far from Jupiter. He concluded that light took time to travel the extra distance. His estimate was surprisingly close to the accepted value today: approximately 300,000 kilometres per second. Light from the Sun reaches Earth in about eight minutes. The nearest star beyond our Sun is over four years of light-travel away.")
        ),
        StoryCategory.Culture to listOf(
            StoryEntry("cul_1", "Tea and Tradition",
                "In many parts of the world, tea is more than a drink — it is a ceremony. In Japan, the tea ceremony called Chado follows precise movements developed over centuries. The host cleans each utensil carefully, whisks the powdered tea, and offers the bowl with both hands. Guests accept it with a bow. Every gesture carries meaning. The ceremony teaches patience, attention, and respect. In a fast-moving world, Chado offers a few minutes of complete stillness."),
            StoryEntry("cul_2", "The Language of Flowers",
                "In Victorian England, flowers carried secret messages. Sending a red rose meant love. Ivy meant fidelity. Yellow carnations expressed rejection. People studied flower dictionaries to decode bouquets given to them. The language of flowers, called floriography, allowed feelings to be communicated without a single spoken word. Though most people today have forgotten the meaning of each flower, the red rose still holds its ancient message wherever it is given."),
            StoryEntry("cul_3", "A Wedding in Two Languages",
                "Nadia's family was from Morocco; her husband's from South Korea. Their wedding took two days. The first evening included traditional Moroccan music, henna patterns on the bride's hands, and a feast of tagine and pastilla. The second day featured a Korean ceremony with silk robes, bowed greetings to elders, and the sharing of rice wine. Guests who spoke only Arabic or only Korean still understood everything. Joy, the couple discovered, is the one universal language."),
            StoryEntry("cul_4", "The Art of Storytelling",
                "Before books, before writing, stories were passed from person to person by word of mouth. A good storyteller was valued in every village. They remembered history, taught morals, and made long nights shorter. In West Africa, these storytellers are called griots. In Central Asia, they are called akyns. In Ireland, they are called seanchaí. Though the names differ, the role is the same: to keep memory alive. In an age of screens, the oldest art form is still the most powerful."),
            StoryEntry("cul_5", "The New Year in Many Ways",
                "People around the world mark the New Year differently. In Spain, the tradition is to eat twelve grapes at midnight — one for each stroke of the clock. In Ethiopia, the New Year falls in September, when the heavy rains stop. In Iran, the celebration of Nowruz begins at the exact moment of the spring equinox. In Japan, temples ring their bells 108 times to release the 108 worries of the past year. Every tradition shares the same hope: that the year ahead will be better than the one just ended.")
        ),
        StoryCategory.Humor to listOf(
            StoryEntry("hum_1", "The Expert",
                "Omar was the only person in the office who could fix the printer. Every time it jammed, people called him. He became famous for it. One day, he was promoted to manager and moved to a different floor. Within a week, the printer broke again. Three engineers spent two days trying to fix it. Finally, they called Omar. He walked over, opened the side panel, and removed a single crumpled receipt. The printer worked immediately. 'Ten years of experience,' he said, and returned to his office."),
            StoryEntry("hum_2", "Lost in Translation",
                "A British tourist in France asked the waiter for 'un verre d'eau' — a glass of water. The waiter brought him wine. He tried again. The waiter frowned and brought him sparkling water. On the third attempt, the tourist stood up and mimed drinking water. The waiter nodded seriously, disappeared into the kitchen, and returned with a glass of milk. The tourist drank it. When he told the story at home, his French friends laughed. His pronunciation, they said, had been requesting something different each time."),
            StoryEntry("hum_3", "The Perfect Excuse",
                "Every year, on the first Monday of April, Yusuf arrived late to work. When asked why, he always said, 'The traffic was terrible.' After five years, his manager finally looked out the window. The street was completely empty. She called Yusuf into her office. He sat down calmly. 'I never said the traffic was terrible today,' he said. 'I said it was terrible. It is terrible. Every day. In general.' His manager was too surprised to argue. He was still late the following year."),
            StoryEntry("hum_4", "The Helpful Neighbour",
                "When Amara asked her neighbour to water her plants while she was away, she left detailed instructions: 'Water the small ones every two days. The big one on the balcony only on Thursdays. The cactus never.' She returned to find the small plants thriving, the big one looking healthier than ever, and the cactus standing in a bucket of water. 'It looked sad,' her neighbour explained. The cactus, somehow, survived."),
            StoryEntry("hum_5", "The Interview",
                "During a job interview, the manager asked: 'Where do you see yourself in five years?' The candidate paused. 'Honestly? In your chair.' The room went quiet. Then the manager laughed. 'That's the most honest answer I've heard in ten years.' He got the job. Three years later, the manager retired. Guess who replaced him.")
        ),
        StoryCategory.Motivation to listOf(
            StoryEntry("mot_1", "One More Step",
                "A runner collapsed near the finish line of a marathon. Medics rushed forward. But she raised her hand. 'I'm fine,' she said. She stood up, slowly, and crossed the line. Afterwards, a journalist asked how she kept going. 'I didn't think about the whole race,' she said. 'I only thought about the next step. And then the next one. That's all a marathon ever is — one more step.'"),
            StoryEntry("mot_2", "The Sculptor",
                "A student asked a famous sculptor how he made such beautiful horses from stone. 'It's simple,' the sculptor said. 'I find a block of stone with a horse inside it, and I remove everything that isn't the horse.' The student laughed, thinking it was a joke. Years later, working on his own first sculpture, he understood: the work is not adding something — it is removing everything that doesn't belong."),
            StoryEntry("mot_3", "The Bamboo Tree",
                "A farmer planted a bamboo seed and watered it every day for four years. Nothing appeared above the ground. Friends told him to stop wasting time. In the fifth year, a shoot appeared. Within six weeks, the bamboo grew to over twenty meters tall. People asked why it had grown so quickly. The farmer smiled. 'It didn't grow in six weeks,' he said. 'It grew in five years. All that time, it was building its roots.'"),
            StoryEntry("mot_4", "The Locked Door",
                "Rania applied for the same scholarship three times and was rejected each time. On the fourth attempt, she wrote a different kind of letter. Instead of listing her achievements, she wrote about what she had learned from failing. She wrote about the courses she took between applications, the people she had helped, and how rejection had made her purpose clearer. She was accepted. The scholarship committee wrote back: 'We didn't reject you three times. We were waiting for you to arrive.'"),
            StoryEntry("mot_5", "The Candle and the Wind",
                "There is an old saying: a candle loses nothing by lighting another candle. A teacher who spent thirty years in a small school shared this with every student on their last day. Some became doctors, some artists, some farmers. One became a teacher too. Years later, that student returned and told her: 'I have lit three hundred candles.' She smiled. 'And I lit one,' she said. 'You.'")
        )
    )

    fun categoryById(id: String): StoryCategory = StoryCategory.fromId(id)
    fun storiesByCategory(category: StoryCategory): List<StoryEntry> = stories[category] ?: emptyList()
}
